postActions.command:
node -e "console.log('
- date: ${date}
- datetime: ${datetime}
- timestamp: ${timestamp}
- year: ${year}
- month: ${month}
- day: ${day}
- time: ${time}
- branch: ${branch}
- commit_hash: ${commit_hash}
- commit_author: ${commit_author}
- last_commit_message: ${last_commit_message}
- tag_count: ${tag_count}
- last_tag: ${last_tag}
- commit_count: ${commit_count}
- version: ${version}
- name: ${name}
- project_version: ${version.vit}
- project_name: ${name.vit}
- node_version: ${node_version}
- os: ${os}
- arch: ${arch}
- cwd: ${cwd}')"

node -e "console.log('
  🎉 Released!
  Version  : ${version.vit}
  Tag      : ${last_tag}
  URL      : ${URL}
  Date     : ${date}
')"
